	coll := client.Database("local_school_district").Collection("schools")
	const indexName = "embedded-documents-tutorial"
	opts := options.SearchIndexes().SetName(indexName).SetType("search")

	// Define the Atlas Search index for embedded documents
	searchIndexModel := mongo.SearchIndexModel{
		Definition: bson.D{
			{"mappings", bson.D{
				{"dynamic", true},
				{"fields", bson.D{
					{"clubs", bson.D{
						{"dynamic", true},
						{"fields", bson.D{
							{"sports", bson.D{
								{"dynamic", true},
								{"type", "embeddedDocuments"},
							}},
						}},
						{"type", "document"},
					}},
					{"teachers", bson.A{
						bson.D{
							{"dynamic", true},
							{"fields", bson.D{
								{"classes", bson.D{
									{"dynamic", true},
									{"type", "embeddedDocuments"},
								}},
							}},
							{"type", "embeddedDocuments"},
						},
						bson.D{
							{"dynamic", true},
							{"fields", bson.D{
								{"classes", bson.D{
									{"dynamic", true},
									{"fields", bson.D{
										{"grade", bson.D{
											{"type", "token"},
										}},
									}},
									{"type", "document"},
								}},
							}},
							{"type", "document"},
						},
					}},
				}},
			}},
		},
